from typing import List, Tuple

Point = Tuple[float, float, float, float]

def convex_hull_4d(points: List[Point]) -> List[Tuple[Point, ...]]:
    if len(points) < 1:
        return []
    if len(points) == 1:
        return [(points[0],)]

    points = np.array(points)
    if np.linalg.matrix_rank(points) < 4:
        return [tuple(points)]

    hull = []
    simplex = []
    visited = set()

    def add_simplex(s):
        nonlocal hull
        hull.append(tuple(s))

    def dfs(idx, s):
        nonlocal simplex, visited
        if len(s) == 5:
            add_simplex(s)
            return
        for i in range(idx, len(points)):
            if i not in visited:
                visited.add(i)
                s.append(points[i])
                dfs(i + 1, s)
                s.pop()

    dfs(0, simplex)
    return hull

