class ConvexHull4D:
    def __init__(self, points):
        self.points = np.array(points)
        self.validate_points()
        self.hull = self.calculate_convex_hull()

    def validate_points(self):
        if len(self.points[0]) != 4:
            raise ValueError("All points must be 4-dimensional")

    def calculate_convex_hull(self):
        simplex = []
        for i in range(5):
            simplex.append(self.points[i])
        hull = self.qhull(simplex, self.points[5:])
        return hull

    def qhull(self, simplex, remaining_points):
        if not remaining_points:
            return simplex

        max_distance = 0
        farthest_point = None
        for point in remaining_points:
            distance = self.distance_to_plane(simplex, point)
            if distance > max_distance:
                max_distance = distance
                farthest_point = point

        if max_distance == 0:
            return simplex

        new_simplex = simplex.copy()
        new_simplex.append(farthest_point)
        remaining_points.remove(farthest_point)

        facets = self.get_facets(new_simplex)
        for facet in facets:
            visible_points = []
            for point in remaining_points:
                if self.is_visible(facet, point):
                    visible_points.append(point)
            new_simplex = self.qhull(new_simplex, visible_points)

        return new_simplex

    def distance_to_plane(self, simplex, point):
        a, b, c, d = simplex
        x0, y0, z0, w0 = a
        x1, y1, z1, w1 = b
        x2, y2, z2, w2 = c
        x3, y3, z3, w3 = d
        x, y, z, w = point

        normal = np.cross(b - a, c - a, d - a)
        return np.abs(np.dot(normal, [x - x0, y - y0, z - z0, w - w0])) / np.linalg.norm(normal)

    def is_visible(self, facet, point):
        a, b, c, d = facet
        x, y, z, w = point
        normal = np.cross(b - a, c - a, d - a)
        return np.dot(normal, [x - a[0], y - a[1], z - a[2], w - a[3]]) > 0

    def get_facets(self, simplex):
        facets = []
        for i in range(4):
            a = simplex[i]
            b = simplex[(i + 1) % 4]
            c = simplex[(i + 2) % 4]
            d = simplex[(i + 3) % 4]
            facets.append([a, b, c, d])
        return facets

