    def is_valid_tetrahedron(self, tetrahedron):
        # Check if all points are of 4 dimensions
        for point in tetrahedron:
            if len(point) != 4:
                return False

        # Check if all points are unique
        if len(set(map(tuple, tetrahedron))) != 4:
            return False

        # Check if the tetrahedron is not degenerate
        if np.linalg.det(np.array([tetrahedron[1] - tetrahedron[0], tetrahedron[2] - tetrahedron[0], tetrahedron[3] - tetrahedron[0]])) == 0:
